// CineWorld - Anime Pipeline
// Full production pipeline for anime series

import React, { useState, useEffect, useContext, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { AuthContext, useTranslations } from '../contexts';
import { TabErrorBoundary } from '../components/ErrorBoundary';
import { Button } from '../components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '../components/ui/card';
import { Input } from '../components/ui/input';
import { Badge } from '../components/ui/badge';
import { Progress } from '../components/ui/progress';
import { Sparkles, ArrowRight, ArrowLeft, Users, Pen, Play, Lock, Loader2, Trash2, Check, Star, ChevronDown, ChevronUp, Film, Clock, Flame, Target, Zap } from 'lucide-react';
import { motion } from 'framer-motion';
import { toast } from 'sonner';
import { ReleaseModeSelector } from '../components/ReleaseModeSelector';

const BACKEND_URL = process.env.REACT_APP_BACKEND_URL;
const posterSrc = (url) => {
  if (!url) return null;
  if (url.startsWith('/')) return `${BACKEND_URL}${url}`;
  return url;
};

const STEPS = [
  { id: 'concept', label: 'Concept', icon: Sparkles, color: 'orange' },
  { id: 'casting', label: 'Casting', icon: Users, color: 'pink' },
  { id: 'screenplay', label: 'Sceneggiatura', icon: Pen, color: 'cyan' },
  { id: 'production', label: 'Produzione', icon: Play, color: 'amber' },
  { id: 'completed', label: 'Completato', icon: Star, color: 'yellow' },
];

const STATUS_TO_STEP = { concept: 0, coming_soon: 0, ready_for_casting: 0, casting: 1, screenplay: 2, production: 3, ready_to_release: 3, completed: 4 };

export default function AnimePipeline() {
  const { api, user, refreshUser } = useContext(AuthContext);
  const navigate = useNavigate();
  const [genres, setGenres] = useState({});
  const [mySeries, setMySeries] = useState([]);
  const [activeSeries, setActiveSeries] = useState(null);
  const [loading, setLoading] = useState(true);
  const [actionLoading, setActionLoading] = useState(false);

  const [title, setTitle] = useState('');
  const [selectedGenre, setSelectedGenre] = useState('');
  const [numEpisodes, setNumEpisodes] = useState(12);
  const [description, setDescription] = useState('');
  const [availableActors, setAvailableActors] = useState([]);
  const [selectedCast, setSelectedCast] = useState([]);
  const [prodStatus, setProdStatus] = useState(null);
  const [castingMode, setCastingMode] = useState(null);
  const [agencyActors, setAgencyActors] = useState({ effective: [], school: [] });
  const [agencyInfo, setAgencyInfo] = useState(null);
  const [releaseType, setReleaseType] = useState(null);
  const [scheduleHours, setScheduleHours] = useState(24);
  const [animeReleaseStrategy, setAnimeReleaseStrategy] = useState(null);
  const [animeManualHours, setAnimeManualHours] = useState(null);
  const [animeCsTier, setAnimeCsTier] = useState('short');
  const [animeCsHours, setAnimeCsHours] = useState(4);

  // Poster + Release states
  const [posterMode, setPosterMode] = useState({});
  const [posterPrompt, setPosterPrompt] = useState({});
  const [posterLoading, setPosterLoading] = useState(null);
  const [expandedPoster, setExpandedPoster] = useState(null);
  const [releaseCard, setReleaseCard] = useState(null);
  const [releasePoster, setReleasePoster] = useState(null);
  const [posterPolling, setPosterPolling] = useState(false);
  const [releasePhase, setReleasePhase] = useState(0);

  const loadData = useCallback(async () => {
    try {
      const [genresRes, seriesRes] = await Promise.all([
        api.get('/series-pipeline/genres?series_type=anime'),
        api.get('/series-pipeline/my?series_type=anime'),
      ]);
      setGenres(genresRes.data.genres || {});
      const series = seriesRes.data.series || [];
      setMySeries(series);
      // Auto-select only series that need interaction (not production)
      setActiveSeries(prev => {
        if (prev) {
          const updated = series.find(s => s.id === prev.id);
          return updated || null;
        }
        const needsAttention = series.find(s => ['concept', 'casting', 'screenplay', 'ready_to_release'].includes(s.status));
        return needsAttention || null;
      });
    } catch (e) { console.error(e); }
    setLoading(false);
  }, [api]);

  useEffect(() => { loadData(); }, [loadData]);

  useEffect(() => {
    if (activeSeries?.status === 'casting') {
      api.get(`/series-pipeline/${activeSeries.id}/available-actors`).then(r => {
        setAvailableActors(r.data.actors || []);
      }).catch(() => {});
      api.get('/agency/actors-for-casting').then(r => {
        setAgencyActors({ effective: r.data.effective_actors || [], school: r.data.school_students || [] });
        setAgencyInfo(r.data);
      }).catch(() => {});
    }
  }, [activeSeries?.status, activeSeries?.id, api]);

  useEffect(() => {
    if (activeSeries?.status === 'production') {
      const poll = () => {
        api.get(`/series-pipeline/${activeSeries.id}/production-status`).then(r => {
          setProdStatus(r.data);
          if (r.data.complete) setActiveSeries(prev => ({ ...prev, status: 'ready_to_release' }));
        }).catch(() => {});
      };
      poll();
      const interval = setInterval(poll, 10000);
      return () => clearInterval(interval);
    }
  }, [activeSeries?.status, activeSeries?.id, api]);

  const createSeries = async () => {
    if (!title.trim() || !selectedGenre) return toast.error('Inserisci titolo e genere');
    setActionLoading(true);
    try {
      const res = await api.post('/series-pipeline/create', {
        title, genre: selectedGenre, num_episodes: numEpisodes,
        series_type: 'anime', description, release_type: releaseType || 'immediate'
      });
      toast.success(`"${title}" creato! Costo: $${res.data.cost?.toLocaleString()}`);
      setActiveSeries(res.data.series);
      setTitle(''); setDescription('');
      await loadData();
      if (refreshUser) refreshUser();
    } catch (e) { toast.error(e.response?.data?.detail || 'Errore'); }
    setActionLoading(false);
  };

  const launchAnimeComingSoon = async () => {
    setActionLoading(true);
    try {
      const res = await api.post(`/series-pipeline/${activeSeries.id}/launch-coming-soon`, {
        tier: animeCsTier || 'short',
        hours: animeCsHours || 4
      });
      toast.success(`${res.data.message} (${res.data.final_hours.toFixed(1)}h)`);
      setActiveSeries(prev => ({ ...prev, status: 'coming_soon', coming_soon_type: 'pre_casting', scheduled_release_at: res.data.scheduled_release_at }));
      loadData();
    } catch (e) { toast.error(e.response?.data?.detail || 'Errore'); }
    setActionLoading(false);
  };

  const advanceToCasting = async () => {
    setActionLoading(true);
    try {
      await api.post(`/series-pipeline/${activeSeries.id}/advance-to-casting`);
      setActiveSeries(prev => ({ ...prev, status: 'casting' }));
    } catch (e) { toast.error(e.response?.data?.detail || 'Errore'); }
    setActionLoading(false);
  };

  const selectCast = async () => {
    if (selectedCast.length === 0) return toast.error('Seleziona almeno una guest star');
    setActionLoading(true);
    try {
      const res = await api.post(`/series-pipeline/${activeSeries.id}/select-cast`, {
        cast: selectedCast.map(c => ({ actor_id: c.actor_id, role: c.role || 'Guest Star Vocale' }))
      });
      toast.success(`Guest Star ingaggiate! Costo: $${res.data.total_salary?.toLocaleString()}`);
      setActiveSeries(prev => ({ ...prev, cast: res.data.cast }));
      setSelectedCast([]);
    } catch (e) { toast.error(e.response?.data?.detail || 'Errore'); }
    setActionLoading(false);
  };

  const submitAgencyCastAnime = async () => {
    const selected = selectedCast.filter(c => c.is_agency);
    if (selected.length === 0) return toast.error("Seleziona almeno un attore dall'agenzia");
    setActionLoading(true);
    try {
      const res = await api.post(`/agency/cast-for-series/${activeSeries.id}`, {
        actor_ids: selected.map(c => ({ actor_id: c.actor_id, role: c.role, source: c.source || 'effective' }))
      });
      toast.success(res.data.message);
      setActiveSeries(prev => ({ ...prev, cast: res.data.cast }));
      setSelectedCast([]);
      loadData();
    } catch (e) { toast.error(e.response?.data?.detail || 'Errore'); }
    setActionLoading(false);
  };

  const advanceToScreenplay = async () => {
    setActionLoading(true);
    try {
      await api.post(`/series-pipeline/${activeSeries.id}/advance-to-screenplay`);
      setActiveSeries(prev => ({ ...prev, status: 'screenplay' }));
    } catch (e) { toast.error(e.response?.data?.detail || 'Errore'); }
    setActionLoading(false);
  };

  const writeScreenplay = async () => {
    setActionLoading(true);
    try {
      const res = await api.post(`/series-pipeline/${activeSeries.id}/write-screenplay`, { mode: 'ai' }, { timeout: 120000 });
      setActiveSeries(prev => ({ ...prev, screenplay: { text: res.data.screenplay } }));
      toast.success('Sceneggiatura generata!');
    } catch (e) { toast.error(e.response?.data?.detail || 'Errore'); }
    setActionLoading(false);
  };

  const startProduction = async () => {
    setActionLoading(true);
    try {
      const res = await api.post(`/series-pipeline/${activeSeries.id}/start-production`);
      setActiveSeries(prev => ({ ...prev, status: 'production', production_duration_minutes: res.data.duration_minutes }));
      toast.success(`Produzione avviata! Durata: ${res.data.duration_minutes} minuti`);
    } catch (e) { toast.error(e.response?.data?.detail || 'Errore'); }
    setActionLoading(false);
  };

  const generateAnimePoster = async (seriesId) => {
    const mode = posterMode[seriesId] || 'ai_auto';
    setPosterLoading(seriesId);
    try {
      const body = { mode };
      if (mode === 'ai_custom') body.custom_prompt = posterPrompt[seriesId] || '';
      const res = await api.post(`/series-pipeline/${seriesId}/generate-poster`, body, { timeout: 120000 });
      toast.success(res.data.message || 'Locandina generata!');
      await loadData();
    } catch (e) { toast.error(e.response?.data?.detail || 'Errore generazione poster'); }
    finally { setPosterLoading(null); }
  };

  const generatePosterQuick = async (seriesId) => {
    setPosterLoading(seriesId);
    try {
      const res = await api.post(`/series-pipeline/${seriesId}/generate-poster`, { mode: 'ai' }, { timeout: 120000 });
      toast.success(res.data.message || 'Locandina generata!');
      await loadData();
    } catch (e) { toast.error(e.response?.data?.detail || 'Errore generazione poster'); }
    finally { setPosterLoading(null); }
  };

  const releaseSeries = async () => {
    setActionLoading(true);
    try {
      const res = await api.post(`/series-pipeline/${activeSeries.id}/release`, {}, { timeout: 60000 });
      setReleaseCard(res.data);
      setReleasePoster(null);
      setPosterPolling(true);
      setReleasePhase(1);
      setTimeout(() => setReleasePhase(2), 1400);
      setTimeout(() => setReleasePhase(3), 3000);
      // Poll for poster
      const seriesId = activeSeries.id;
      let attempts = 0;
      const pollInterval = setInterval(async () => {
        attempts++;
        try {
          const posterRes = await api.get(`/series-pipeline/${seriesId}/poster-status`);
          if (posterRes.data.ready && posterRes.data.poster_url) {
            setReleasePoster(posterRes.data.poster_url);
            setPosterPolling(false);
            clearInterval(pollInterval);
          }
        } catch {}
        if (attempts >= 30) { setPosterPolling(false); clearInterval(pollInterval); }
      }, 2000);
      if (refreshUser) refreshUser();
    } catch (e) { toast.error(e.response?.data?.detail || 'Errore nel rilascio'); }
    setActionLoading(false);
  };

  const closeReleaseCard = () => {
    setReleaseCard(null);
    setReleasePoster(null);
    setPosterPolling(false);
    setReleasePhase(0);
    setActiveSeries(null);
    loadData();
  };

  const discardSeries = async () => {
    if (!window.confirm('Vuoi cancellare questo anime? Rimborso 50%.')) return;
    setActionLoading(true);
    try {
      const res = await api.post(`/series-pipeline/${activeSeries.id}/discard`);
      toast.success(`Anime cancellato. Rimborso: $${res.data.refund?.toLocaleString()}`);
      setActiveSeries(null);
      loadData();
    } catch (e) { toast.error(e.response?.data?.detail || 'Errore'); }
    setActionLoading(false);
  };

  const toggleCastMember = (actor, role) => {
    setSelectedCast(prev => {
      const exists = prev.find(c => c.actor_id === actor.id);
      if (exists) return prev.filter(c => c.actor_id !== actor.id);
      return [...prev, { actor_id: actor.id, name: actor.name, role, skill: actor.skill }];
    });
  };

  const currentStep = activeSeries ? (STATUS_TO_STEP[activeSeries.status] ?? 0) : -1;

  if (loading) return (
    <div className="min-h-screen bg-[#0A0A0B] flex items-center justify-center">
      <Loader2 className="w-8 h-8 text-orange-400 animate-spin" />
    </div>
  );

  return (
    <div className="min-h-screen bg-[#0A0A0B] text-white pb-20 pt-16">
      <div className="max-w-2xl mx-auto px-3">
        {/* Header */}
        <div className="flex items-center gap-3 mb-4 mt-2">
          <div className="p-2.5 bg-orange-500/20 rounded-xl border border-orange-500/30">
            <Sparkles className="w-6 h-6 text-orange-400" />
          </div>
          <div>
            <h1 className="font-['Bebas_Neue'] text-2xl text-orange-400" data-testid="anime-pipeline-title">Pipeline Anime</h1>
            <p className="text-xs text-gray-500">Produci il tuo anime originale</p>
          </div>
        </div>

        {/* Step Progress */}
        {activeSeries && (
          <div className="flex items-center gap-1 mb-4 px-1" data-testid="anime-steps">
            {STEPS.map((step, i) => (
              <React.Fragment key={step.id}>
                <div className={`flex items-center gap-1 px-2 py-1 rounded-lg text-[10px] font-semibold transition-all ${
                  i === currentStep ? 'bg-orange-500/20 text-orange-400 border border-orange-500/30' :
                  i < currentStep ? 'bg-white/5 text-gray-400' : 'bg-white/[0.02] text-gray-600'
                }`}>
                  {i < currentStep ? <Check className="w-3 h-3" /> : <step.icon className="w-3 h-3" />}
                  <span className="hidden sm:inline">{step.label}</span>
                </div>
                {i < STEPS.length - 1 && <div className={`flex-1 h-px ${i < currentStep ? 'bg-white/20' : 'bg-white/5'}`} />}
              </React.Fragment>
            ))}
          </div>
        )}

        {/* In-production anime cards (visible when creating new ones) */}
        {!activeSeries && mySeries.filter(s => s.status === 'production').length > 0 && (
          <div className="space-y-2 mb-4">
            <h3 className="text-xs font-semibold text-gray-500 uppercase">In Produzione</h3>
            {mySeries.filter(s => s.status === 'production').map(s => (
              <Card key={s.id} className="bg-[#111113] border-amber-500/10 cursor-pointer hover:border-amber-500/30 transition-colors"
                onClick={() => setActiveSeries(s)}
                data-testid={`production-anime-${s.id}`}>
                <CardContent className="p-2.5 flex items-center gap-2">
                  <div className="w-8 h-8 rounded-lg bg-amber-500/10 flex items-center justify-center flex-shrink-0">
                    <Play className="w-4 h-4 text-amber-400" />
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-xs font-bold truncate">{s.title}</p>
                    <p className="text-[9px] text-gray-500">{s.genre_name} - {s.num_episodes} ep.</p>
                  </div>
                  <Badge className="bg-amber-500/20 text-amber-400 text-[9px] flex-shrink-0">In Produzione</Badge>
                </CardContent>
              </Card>
            ))}
          </div>
        )}

        {!activeSeries ? (
          <div className="space-y-4">
            {/* Step 0: Release Mode Selection */}
            {!releaseType && (
              <Card className="bg-[#111113] border-orange-500/20" data-testid="anime-release-mode-card">
                <CardContent className="p-4">
                  <ReleaseModeSelector selected={releaseType} onSelect={setReleaseType} onContinue={() => {}} />
                </CardContent>
              </Card>
            )}

            {releaseType && (
            <Card className="bg-[#111113] border-orange-500/20" data-testid="create-anime-form">
              <CardHeader className="pb-2">
                <div className="flex items-center justify-between">
                  <CardTitle className="text-lg font-['Bebas_Neue'] text-orange-400">Nuovo Anime</CardTitle>
                  <button onClick={() => setReleaseType(null)} className="flex items-center gap-1 text-[9px] text-gray-500 hover:text-orange-400 transition-colors" data-testid="anime-change-release-mode-btn">
                    {releaseType === 'coming_soon' ? <Clock className="w-3 h-3 text-cyan-400" /> : <Flame className="w-3 h-3 text-yellow-400" />}
                    {releaseType === 'coming_soon' ? 'Coming Soon' : 'Immediato'}
                  </button>
                </div>
              </CardHeader>
              <CardContent className="space-y-3">
                <Input placeholder="Titolo dell'anime" value={title} onChange={e => setTitle(e.target.value)} className="bg-white/5 border-white/10 text-white" data-testid="anime-title-input" />
                <div>
                  <label className="text-xs text-gray-400 mb-1.5 block">Genere</label>
                  <div className="grid grid-cols-2 gap-1.5">
                    {Object.entries(genres).map(([key, g]) => (
                      <button key={key}
                        className={`px-3 py-2 rounded-lg text-xs font-medium transition-all text-left ${selectedGenre === key ? 'bg-orange-500 text-white' : 'bg-white/5 text-gray-400 hover:bg-white/10 border border-white/5'}`}
                        onClick={() => { setSelectedGenre(key); setNumEpisodes(g.ep_range[0]); }}
                        data-testid={`anime-genre-${key}`}
                      >
                        <span className="block font-semibold">{g.name_it}</span>
                        {g.desc && <span className="block text-[9px] opacity-70 mt-0.5">{g.desc}</span>}
                      </button>
                    ))}
                  </div>
                </div>
                {selectedGenre && (
                  <div>
                    <label className="text-xs text-gray-400 mb-1 block">
                      Episodi ({genres[selectedGenre]?.ep_range[0]}-{genres[selectedGenre]?.ep_range[1]})
                    </label>
                    <div className="flex items-center gap-2">
                      <input type="range"
                        min={genres[selectedGenre]?.ep_range[0]}
                        max={genres[selectedGenre]?.ep_range[1]}
                        value={numEpisodes}
                        onChange={e => setNumEpisodes(parseInt(e.target.value))}
                        className="flex-1 accent-orange-500"
                        data-testid="anime-episodes-slider"
                      />
                      <span className="text-sm font-bold text-orange-400 w-8 text-center">{numEpisodes}</span>
                    </div>
                    <p className="text-[10px] text-gray-500 mt-1">
                      Costo: ${((numEpisodes * 80000 * (genres[selectedGenre]?.cost_mult || 1))).toLocaleString()} | Produzione: {numEpisodes * 12} min
                    </p>
                  </div>
                )}
                <Input placeholder="Descrizione (opzionale)" value={description} onChange={e => setDescription(e.target.value)} className="bg-white/5 border-white/10 text-white" data-testid="anime-description-input" />
                <Button className="w-full bg-orange-500 hover:bg-orange-600 text-white" onClick={createSeries} disabled={actionLoading || !title.trim() || !selectedGenre} data-testid="create-anime-btn">
                  {actionLoading ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : <Sparkles className="w-4 h-4 mr-2" />}
                  Crea Anime
                </Button>
              </CardContent>
            </Card>
            )}

            {mySeries.filter(s => s.status === 'completed').length > 0 && (
              <div>
                <h3 className="text-sm font-semibold text-gray-400 mb-2">Anime Completati</h3>
                <div className="space-y-2">
                  {mySeries.filter(s => s.status === 'completed').map(s => (
                    <Card key={s.id} className="bg-[#111113] border-white/5 cursor-pointer hover:border-white/15 transition-colors" data-testid={`completed-anime-${s.id}`}
                      onClick={() => navigate(`/series/${s.id}`)}>
                      <CardContent className="p-3">
                        <div className="flex items-center gap-3">
                          {s.poster_url ? (
                            <img src={posterSrc(s.poster_url)} alt="" className="w-12 h-16 rounded object-cover" loading="lazy" />
                          ) : (
                            <div className="w-12 h-16 rounded bg-orange-500/10 flex items-center justify-center border border-orange-500/20">
                              <Film className="w-5 h-5 text-orange-400/50" />
                            </div>
                          )}
                          <div className="flex-1 min-w-0">
                            <p className="text-sm font-bold truncate">{s.title}</p>
                            <p className="text-[10px] text-gray-500">{s.genre_name} - {s.num_episodes} ep.</p>
                          </div>
                          <div className="flex items-center gap-2">
                            <Badge className="bg-yellow-500/20 text-yellow-400 text-[10px]">{s.quality_score}/100</Badge>
                            <button onClick={(e) => { e.stopPropagation(); setExpandedPoster(expandedPoster === s.id ? null : s.id); }}
                              className="p-1.5 rounded-lg bg-orange-500/10 hover:bg-orange-500/20 text-orange-400 transition-all"
                              data-testid={`anime-poster-toggle-${s.id}`}>
                              <Sparkles className="w-3.5 h-3.5" />
                            </button>
                          </div>
                        </div>
                        {/* Poster management for completed anime */}
                        {expandedPoster === s.id && (
                          <div className="mt-3 p-2.5 rounded-lg border border-orange-500/20 bg-orange-500/5">
                            <p className="text-[10px] text-orange-400 font-semibold mb-2">
                              {s.poster_url ? 'Rigenera Locandina' : 'Crea Locandina'}
                            </p>
                            {s.poster_url && (
                              <div className="flex justify-center mb-2">
                                <img src={posterSrc(s.poster_url)} alt="" className="w-20 h-28 object-cover rounded border border-orange-500/20" />
                              </div>
                            )}
                            <div className="flex gap-1 mb-2">
                              {[{ id: 'ai_auto', label: 'AI Automatica' }, { id: 'ai_custom', label: 'AI + Prompt' }].map(opt => (
                                <button key={opt.id} onClick={() => setPosterMode(p => ({...p, [s.id]: opt.id}))}
                                  className={`flex-1 p-1.5 rounded text-center border transition-all text-[9px] ${(posterMode[s.id] || 'ai_auto') === opt.id ? 'border-orange-500 bg-orange-500/10 text-orange-300' : 'border-gray-700 text-gray-400'}`}
                                  data-testid={`anime-poster-mode-${opt.id}-${s.id}`}>
                                  {opt.label}
                                </button>
                              ))}
                            </div>
                            {(posterMode[s.id] || 'ai_auto') === 'ai_custom' && (
                              <input type="text" placeholder="Descrivi la locandina che vuoi..."
                                value={posterPrompt[s.id] || ''} onChange={e => setPosterPrompt(p => ({...p, [s.id]: e.target.value}))}
                                className="w-full mb-2 text-[10px] bg-black/30 border border-gray-700 rounded p-1.5 text-white"
                                data-testid={`anime-poster-prompt-${s.id}`} />
                            )}
                            <Button size="sm" className="w-full bg-orange-600 hover:bg-orange-700 text-[10px] h-7"
                              onClick={() => generateAnimePoster(s.id)} disabled={posterLoading === s.id}
                              data-testid={`anime-generate-poster-${s.id}`}>
                              {posterLoading === s.id ? <Loader2 className="w-3 h-3 animate-spin mr-1" /> : <Sparkles className="w-3 h-3 mr-1" />}
                              {s.poster_url ? 'Rigenera Locandina' : 'Crea Locandina'}
                            </Button>
                          </div>
                        )}
                      </CardContent>
                    </Card>
                  ))}
                </div>
              </div>
            )}
          </div>
        ) : (
          <TabErrorBoundary name="anime-pipeline">
          <div className="space-y-3" data-testid="active-anime-pipeline">
            {/* Back button */}
            <button onClick={() => setActiveSeries(null)}
              className="flex items-center gap-1 text-xs text-gray-500 hover:text-orange-400 transition-colors mb-1"
              data-testid="anime-back-to-projects-btn">
              <ArrowLeft className="w-3 h-3" /> Tutti i progetti
            </button>

            {/* Anime Header */}
            <Card className="bg-[#111113] border-orange-500/20">
              <CardContent className="p-3 flex items-center gap-3">
                {activeSeries.poster_url ? (
                  <img src={posterSrc(activeSeries.poster_url)} alt="" className="w-16 h-24 rounded-lg object-cover" />
                ) : (
                  <div className="w-16 h-24 rounded-lg bg-orange-500/10 flex items-center justify-center border border-orange-500/20">
                    <Sparkles className="w-8 h-8 text-orange-400/50" />
                  </div>
                )}
                <div className="flex-1 min-w-0">
                  <h2 className="text-lg font-bold truncate" data-testid="active-anime-title">{activeSeries.title}</h2>
                  <p className="text-xs text-gray-400">{activeSeries.genre_name} - {activeSeries.num_episodes} episodi</p>
                  <Badge className="bg-orange-500/20 text-orange-400 text-[10px] mt-1">{activeSeries.status}</Badge>
                </div>
                <button onClick={discardSeries} className="p-2 text-red-400/60 hover:text-red-400" data-testid="discard-anime-btn">
                  <Trash2 className="w-4 h-4" />
                </button>
              </CardContent>
            </Card>

            {/* CONCEPT / COMING SOON PRE-CASTING */}
            {(activeSeries.status === 'concept' || activeSeries.status === 'ready_for_casting' || (activeSeries.status === 'coming_soon' && activeSeries.coming_soon_type === 'pre_casting')) && (() => {
              const hasPoster = !!activeSeries.poster_url;
              const isComingSoon = activeSeries.status === 'coming_soon';
              const csExpired = activeSeries.status === 'ready_for_casting' || (isComingSoon && activeSeries.scheduled_release_at && new Date(activeSeries.scheduled_release_at) <= new Date());
              return (
              <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}>
                <Card className="bg-[#111113] border-orange-500/10">
                  <CardContent className="p-4 space-y-3">
                    <div className="flex items-center gap-1 mb-1">
                      <div className={`h-1 flex-1 rounded-full ${!hasPoster ? 'bg-purple-500' : 'bg-purple-500/30'}`} />
                      <div className={`h-1 flex-1 rounded-full ${hasPoster && !isComingSoon ? 'bg-cyan-500' : isComingSoon ? 'bg-cyan-500/30' : 'bg-gray-700'}`} />
                      <div className={`h-1 flex-1 rounded-full ${isComingSoon && !csExpired ? 'bg-orange-500 animate-pulse' : csExpired ? 'bg-green-500' : 'bg-gray-700'}`} />
                    </div>

                    {!hasPoster && (
                      <div className="space-y-2 text-center" data-testid="anime-poster-step">
                        <Sparkles className="w-8 h-8 text-purple-400 mx-auto" />
                        <p className="text-xs text-gray-300 font-semibold">Genera la locandina</p>
                        <Button className="w-full bg-purple-700 hover:bg-purple-600 text-xs"
                          onClick={() => generateAnimePoster(activeSeries.id)} disabled={posterLoading === activeSeries.id}
                          data-testid="gen-anime-poster-btn">
                          {posterLoading === activeSeries.id ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : <Sparkles className="w-4 h-4 mr-2" />}
                          Genera Locandina
                        </Button>
                      </div>
                    )}

                    {hasPoster && !isComingSoon && (
                      <div className="space-y-2" data-testid="anime-launch-cs">
                        <img src={activeSeries.poster_url?.startsWith('/') ? `${process.env.REACT_APP_BACKEND_URL}${activeSeries.poster_url}` : activeSeries.poster_url}
                          alt="" className="w-20 h-28 object-cover rounded mx-auto" />
                        <p className="text-[10px] font-bold text-cyan-400 text-center">Durata Coming Soon</p>
                        <div className="grid grid-cols-3 gap-1">
                          {[{id:'short',l:'Breve',r:'2-6h'},{id:'medium',l:'Medio',r:'6-18h'},{id:'long',l:'Lungo',r:'18-48h'}].map(t => (
                            <button key={t.id} onClick={() => { setAnimeCsTier(t.id); setAnimeCsHours(t.id === 'short' ? 4 : t.id === 'medium' ? 12 : 30); }}
                              className={`p-1.5 rounded border text-center text-[9px] transition-all ${animeCsTier === t.id ? 'border-cyan-500/60 bg-cyan-500/10 text-cyan-300' : 'border-gray-700 text-gray-500'}`}>
                              <p className="font-bold">{t.l}</p><p className="text-[8px]">{t.r}</p>
                            </button>
                          ))}
                        </div>
                        <div className="flex gap-1">
                          {(animeCsTier === 'short' ? [2,3,4,5,6] : animeCsTier === 'medium' ? [6,8,10,12,15,18] : [18,24,30,36,42,48]).map(h => (
                            <button key={h} onClick={() => setAnimeCsHours(h)}
                              className={`flex-1 py-1 rounded text-[8px] border ${animeCsHours === h ? 'border-cyan-500 bg-cyan-500/15 text-cyan-400' : 'border-gray-700 text-gray-500'}`}>
                              {h}h
                            </button>
                          ))}
                        </div>
                        <Button className="w-full bg-cyan-600 hover:bg-cyan-500 text-xs"
                          onClick={launchAnimeComingSoon} disabled={actionLoading}
                          data-testid="launch-anime-cs-btn">
                          {actionLoading ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : <Clock className="w-4 h-4 mr-2" />}
                          Lancia Coming Soon ({animeCsHours}h)
                        </Button>
                      </div>
                    )}

                    {isComingSoon && !csExpired && (
                      <div className="text-center space-y-2" data-testid="anime-cs-active">
                        <Flame className="w-8 h-8 text-orange-400 mx-auto animate-pulse" />
                        <p className="text-sm font-bold text-orange-400">Coming Soon attivo!</p>
                        <p className="text-[10px] text-gray-500">Il casting iniziera' dopo il Coming Soon</p>
                        {activeSeries.hype_score > 0 && <p className="text-[10px] text-orange-400">Hype: {activeSeries.hype_score}</p>}
                      </div>
                    )}

                    {csExpired && (
                      <div className="text-center space-y-2" data-testid="anime-casting-ready">
                        <div className="p-2 rounded-lg border border-green-500/20 bg-green-500/5">
                          <p className="text-xs font-bold text-green-400">Coming Soon completato!</p>
                          {activeSeries.hype_score > 0 && <p className="text-[9px] text-orange-400">Hype accumulato: {activeSeries.hype_score}</p>}
                        </div>
                        <Button className="w-full bg-orange-500 hover:bg-orange-600" onClick={advanceToCasting} disabled={actionLoading} data-testid="anime-advance-casting-btn">
                          Vai al Casting <ArrowRight className="w-4 h-4 ml-2" />
                        </Button>
                      </div>
                    )}
                  </CardContent>
                </Card>
              </motion.div>
              );
            })()}

            {/* CASTING */}
            {activeSeries.status === 'casting' && (
              <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} className="space-y-3">
                {activeSeries.cast?.length > 0 && (
                  <Card className="bg-[#111113] border-pink-500/10">
                    <CardHeader className="pb-1"><CardTitle className="text-sm text-pink-400">Cast Selezionato</CardTitle></CardHeader>
                    <CardContent className="p-3 pt-0">
                      {activeSeries.cast.map((c, i) => (
                        <div key={i} className="flex items-center justify-between text-xs bg-pink-500/5 rounded-lg px-2 py-1.5 mb-1">
                          <span className="font-medium">{c.name}</span>
                          <div className="flex items-center gap-1">
                            <Badge className="text-[9px] bg-white/5">{c.role}</Badge>
                            {c.is_agency_actor && <Badge className="text-[7px] bg-purple-500/20 text-purple-400">Agenzia</Badge>}
                          </div>
                        </div>
                      ))}
                    </CardContent>
                  </Card>
                )}

                {/* Casting mode choice - Anime: Guest Star Vocali */}
                {!castingMode && (
                  <div className="p-3 rounded-lg border border-pink-500/20 bg-pink-500/5 space-y-2" data-testid="anime-casting-mode-choice">
                    <p className="text-xs font-semibold text-pink-300">Guest Star Vocali (Opzionale)</p>
                    <p className="text-[9px] text-gray-400">Ingaggia attori famosi per dare la voce ai personaggi! Costa molto ma migliora qualità e fama.</p>
                    <div className="grid grid-cols-2 gap-2">
                      {(agencyActors.effective.length > 0 || agencyActors.school.length > 0) && (
                        <Button size="sm" className="h-auto py-2 bg-purple-600 hover:bg-purple-700 text-left flex-col items-start"
                          onClick={() => setCastingMode('agency')} data-testid="anime-cast-agency">
                          <span className="text-xs font-semibold flex items-center gap-1"><Users className="w-3.5 h-3.5" /> Dalla tua Agenzia</span>
                          <span className="text-[9px] text-purple-200/70 mt-0.5">{agencyActors.effective.length + agencyActors.school.length} attori</span>
                        </Button>
                      )}
                      <Button size="sm" className="h-auto py-2 bg-pink-600 hover:bg-pink-700 text-left flex-col items-start"
                        onClick={() => setCastingMode('market')} data-testid="anime-cast-market">
                        <span className="text-xs font-semibold flex items-center gap-1"><Star className="w-3.5 h-3.5" /> Guest Star Famose</span>
                        <span className="text-[9px] text-pink-200/70 mt-0.5">Solo attori celebri</span>
                      </Button>
                    </div>
                    <Button size="sm" variant="outline" className="w-full text-xs text-gray-400 border-white/10 hover:bg-white/5 mt-1"
                      onClick={advanceToScreenplay} disabled={actionLoading} data-testid="anime-skip-casting">
                      {actionLoading ? <Loader2 className="w-3.5 h-3.5 animate-spin mr-1" /> : <ArrowRight className="w-3.5 h-3.5 mr-1" />}
                      Procedi senza Guest Star
                    </Button>
                  </div>
                )}

                {/* Agency casting for anime */}
                {castingMode === 'agency' && (
                  <Card className="bg-[#111113] border-purple-500/10">
                    <CardHeader className="pb-1">
                      <div className="flex items-center justify-between">
                        <CardTitle className="text-sm text-purple-400">I tuoi Attori come Guest Star</CardTitle>
                        <Button size="sm" variant="ghost" className="h-6 text-[9px] text-gray-400" onClick={() => setCastingMode('market')}>Guest Star dal Mercato</Button>
                      </div>
                    </CardHeader>
                    <CardContent className="p-3 pt-0">
                      <div className="space-y-1.5 max-h-60 overflow-y-auto">
                        {[...agencyActors.effective.map(a => ({...a, _source: 'effective'})), ...agencyActors.school.map(a => ({...a, _source: 'school'}))].map(actor => {
                          const alreadyCast = activeSeries.cast?.some(c => c.actor_id === actor.id);
                          const isSelected = selectedCast.find(c => c.actor_id === actor.id);
                          const skills = actor.skills || {};
                          const avgSkill = Object.values(skills).length > 0
                            ? Math.round(Object.values(skills).reduce((a, b) => a + b, 0) / Object.values(skills).length) : 0;
                          return (
                            <div key={actor.id} className={`flex items-center gap-2 p-2 rounded-lg cursor-pointer border ${
                              alreadyCast ? 'bg-green-500/5 border-green-500/20 opacity-60' : isSelected ? 'bg-purple-500/15 border-purple-500/30' : 'bg-white/[0.02] border-white/5 hover:bg-white/5'
                            }`} onClick={() => !alreadyCast && setSelectedCast(prev => {
                              const exists = prev.find(c => c.actor_id === actor.id);
                              if (exists) return prev.filter(c => c.actor_id !== actor.id);
                              return [...prev, { actor_id: actor.id, name: actor.name, role: 'Guest Star Vocale', is_agency: true, source: actor._source }];
                            })} data-testid={`anime-agency-actor-${actor.id}`}>
                              <div className={`w-8 h-8 rounded-full flex items-center justify-center text-xs font-bold ${actor._source === 'school' ? 'bg-cyan-500/20 text-cyan-400' : 'bg-purple-500/20 text-purple-400'}`}>
                                {actor.name?.charAt(0)}
                              </div>
                              <div className="flex-1 min-w-0">
                                <div className="flex items-center gap-1">
                                  <p className="text-xs font-medium truncate">{actor.name}</p>
                                  {actor._source === 'school' && <Badge className="text-[7px] bg-cyan-500/15 text-cyan-400 h-3.5">Studente</Badge>}
                                  <Badge className="text-[7px] bg-pink-500/15 text-pink-400 h-3.5">Guest Star</Badge>
                                </div>
                                <div className="flex items-center gap-1 flex-wrap">
                                  <span className="text-[9px] text-gray-500">Skill: {avgSkill}</span>
                                  {(actor.strong_genres_names || []).map((g, i) => <Badge key={i} className="bg-emerald-500/15 text-emerald-400 text-[6px] h-3">{g}</Badge>)}
                                </div>
                              </div>
                              {isSelected && <Check className="w-4 h-4 text-purple-400" />}
                              {alreadyCast && <Badge className="text-[8px] bg-green-500/20 text-green-400">Nel cast</Badge>}
                            </div>
                          );
                        })}
                      </div>
                      {selectedCast.filter(c => c.is_agency).length > 0 && (
                        <Button className="w-full mt-2 bg-purple-500 hover:bg-purple-600" onClick={submitAgencyCastAnime} disabled={actionLoading} data-testid="anime-confirm-agency-cast">
                          {actionLoading ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : <Users className="w-4 h-4 mr-2" />}
                          Conferma Guest Star dall'Agenzia ({selectedCast.filter(c => c.is_agency).length})
                        </Button>
                      )}
                      <p className="text-[9px] text-amber-400 mt-1">Bonus: +20-70% XP e Fama con i tuoi attori!</p>
                      <Button size="sm" variant="outline" className="w-full text-[10px] text-gray-400 border-white/10 hover:bg-white/5 mt-2"
                        onClick={advanceToScreenplay} disabled={actionLoading}>
                        Procedi senza altre Guest Star <ArrowRight className="w-3 h-3 ml-1" />
                      </Button>
                    </CardContent>
                  </Card>
                )}

                {/* Market casting — Guest Star Famose */}
                {castingMode === 'market' && (
                <Card className="bg-[#111113] border-pink-500/10">
                  <CardHeader className="pb-1">
                    <div className="flex items-center justify-between">
                      <CardTitle className="text-sm text-pink-400">Guest Star Vocali</CardTitle>
                      <div className="flex gap-1">
                        {(agencyActors.effective.length > 0 || agencyActors.school.length > 0) && (
                          <Button size="sm" variant="ghost" className="h-6 text-[9px] text-gray-400" onClick={() => setCastingMode('agency')}>I tuoi Attori</Button>
                        )}
                      </div>
                    </div>
                    <p className="text-[9px] text-gray-500 mt-1">Attori famosi che prestano la voce ai personaggi. Costano molto ma danno un bonus qualità e fama!</p>
                  </CardHeader>
                  <CardContent className="p-3 pt-0 space-y-3">
                    {availableActors.length === 0 ? (
                      <p className="text-xs text-gray-500 text-center py-4">Nessuna guest star disponibile al momento.</p>
                    ) : (
                      <div className="space-y-1.5 max-h-[400px] overflow-y-auto">
                        {availableActors.map(actor => {
                          const isSelected = selectedCast.find(c => c.actor_id === actor.id);
                          const alreadyCast = activeSeries.cast?.some(c => c.actor_id === actor.id);
                          const skills = actor.skills || {};
                          const avgSkill = Object.values(skills).length > 0
                            ? Math.round(Object.values(skills).reduce((a, b) => a + b, 0) / Object.values(skills).length) : actor.skill || 50;
                          return (
                            <div key={actor.id} className={`p-2 rounded-lg transition-all border ${
                              alreadyCast ? 'bg-green-500/5 border-green-500/20 opacity-60' : isSelected ? 'bg-pink-500/15 border-pink-500/30' : 'bg-white/[0.02] border-white/5 hover:bg-white/5'
                            }`} data-testid={`anime-guest-star-${actor.id}`}>
                              <div className="flex items-center gap-2 cursor-pointer" onClick={() => !alreadyCast && toggleCastMember(actor, 'Guest Star Vocale')}>
                                {actor.avatar_url ? (
                                  <img src={actor.avatar_url} alt="" className="w-9 h-9 rounded-full bg-gray-800" />
                                ) : (
                                  <div className="w-9 h-9 rounded-full bg-yellow-500/20 flex items-center justify-center text-xs font-bold text-yellow-400">{actor.name?.charAt(0)}</div>
                                )}
                                <div className="flex-1 min-w-0">
                                  <div className="flex items-center gap-1">
                                    <p className="text-xs font-semibold truncate">{actor.name}</p>
                                    <span className={`text-[10px] font-bold ${actor.gender === 'female' ? 'text-pink-400' : 'text-cyan-400'}`}>{actor.gender === 'female' ? '\u2640' : '\u2642'}</span>
                                    <Badge className={`text-[6px] h-3 ${actor.fame_category === 'superstar' ? 'bg-yellow-500/20 text-yellow-400' : 'bg-orange-500/20 text-orange-400'}`}>
                                      {actor.fame_category === 'superstar' ? 'Superstar' : 'Famoso'}
                                    </Badge>
                                    {[...Array(actor.stars || 4)].map((_, i) => <Star key={i} className="w-2.5 h-2.5 text-yellow-500 fill-yellow-500" />)}
                                  </div>
                                  <p className="text-[9px] text-gray-500">{actor.nationality} {actor.age ? `\u2022 ${actor.age} anni` : ''} \u2022 Skill: <span className="text-emerald-400">{avgSkill}</span></p>
                                  <div className="flex flex-wrap gap-0.5 mt-0.5">
                                    {(actor.strong_genres_names || []).map((g, i) => <Badge key={i} className="bg-emerald-500/15 text-emerald-400 text-[6px] h-3">{g}</Badge>)}
                                    {actor.adaptable_genre_name && <Badge className="bg-amber-500/15 text-amber-400 text-[6px] h-3">~ {actor.adaptable_genre_name}</Badge>}
                                  </div>
                                </div>
                                <div className="flex flex-col items-end gap-1 flex-shrink-0">
                                  <span className="text-[9px] text-red-400 font-bold">${(actor.salary || 0).toLocaleString()}</span>
                                  <Badge className="text-[6px] bg-pink-500/15 text-pink-400 h-3">Guest Star</Badge>
                                  {isSelected && <Check className="w-3.5 h-3.5 text-pink-400" />}
                                  {alreadyCast && <Badge className="text-[7px] bg-green-500/20 text-green-400">Nel cast</Badge>}
                                </div>
                              </div>
                            </div>
                          );
                        })}
                      </div>
                    )}
                    {selectedCast.filter(c => !c.is_agency).length > 0 && (
                      <Button className="w-full mt-2 bg-pink-500 hover:bg-pink-600" onClick={selectCast} disabled={actionLoading} data-testid="anime-confirm-guest-stars-btn">
                        {actionLoading ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : <Star className="w-4 h-4 mr-2" />}
                        Ingaggia Guest Star ({selectedCast.filter(c => !c.is_agency).length}) — ${selectedCast.filter(c => !c.is_agency).reduce((sum, c) => sum + ((availableActors.find(a => a.id === c.actor_id) || {}).salary || 0), 0).toLocaleString()}
                      </Button>
                    )}
                    <Button size="sm" variant="outline" className="w-full text-[10px] text-gray-400 border-white/10 hover:bg-white/5"
                      onClick={advanceToScreenplay} disabled={actionLoading} data-testid="anime-skip-guest-stars">
                      {actionLoading ? <Loader2 className="w-3.5 h-3.5 animate-spin mr-1" /> : <ArrowRight className="w-3.5 h-3.5 mr-1" />}
                      Procedi senza Guest Star
                    </Button>
                  </CardContent>
                </Card>
                )}
                {activeSeries.cast?.length > 0 && castingMode && (
                  <Button className="w-full bg-cyan-500 hover:bg-cyan-600" onClick={advanceToScreenplay} disabled={actionLoading} data-testid="anime-advance-screenplay-btn">
                    Vai alla Sceneggiatura <ArrowRight className="w-4 h-4 ml-2" />
                  </Button>
                )}
              </motion.div>
            )}

            {/* SCREENPLAY */}
            {activeSeries.status === 'screenplay' && (
              <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} className="space-y-3">
                <Card className="bg-[#111113] border-cyan-500/10">
                  <CardHeader className="pb-1"><CardTitle className="text-sm text-cyan-400">Sceneggiatura</CardTitle></CardHeader>
                  <CardContent className="p-3 pt-0 space-y-3">
                    {activeSeries.screenplay?.text ? (
                      <div className="bg-black/30 rounded-lg p-3 max-h-64 overflow-y-auto">
                        <p className="text-xs text-gray-300 whitespace-pre-line">{activeSeries.screenplay.text}</p>
                      </div>
                    ) : (
                      <div className="text-center py-6">
                        <Pen className="w-8 h-8 text-cyan-400/40 mx-auto mb-2" />
                        <p className="text-xs text-gray-500 mb-3">Genera la sceneggiatura del tuo anime con l'AI</p>
                        <Button className="bg-cyan-500 hover:bg-cyan-600" onClick={writeScreenplay} disabled={actionLoading} data-testid="anime-generate-screenplay-btn">
                          {actionLoading ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : <Pen className="w-4 h-4 mr-2" />}
                          Genera Sceneggiatura AI
                        </Button>
                      </div>
                    )}
                  </CardContent>
                </Card>
                {activeSeries.screenplay?.text && (
                  <Button className="w-full bg-amber-500 hover:bg-amber-600 text-black font-bold" onClick={startProduction} disabled={actionLoading} data-testid="anime-start-production-btn">
                    {actionLoading ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : <Play className="w-4 h-4 mr-2" />}
                    Avvia Produzione
                  </Button>
                )}
              </motion.div>
            )}

            {/* PRODUCTION */}
            {(activeSeries.status === 'production' || activeSeries.status === 'ready_to_release') && (
              <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} className="space-y-3">
                <Card className="bg-[#111113] border-amber-500/10">
                  <CardContent className="p-4 space-y-3">
                    <div className="flex items-center justify-between">
                      <span className="text-sm font-semibold text-amber-400">Produzione Anime</span>
                      <span className="text-xs text-gray-400">
                        {prodStatus?.complete || activeSeries.status === 'ready_to_release' ? 'Completata!' : `${prodStatus?.remaining_minutes?.toFixed(0) || '?'} min`}
                      </span>
                    </div>
                    <Progress value={prodStatus?.progress || (activeSeries.status === 'ready_to_release' ? 100 : 0)} className="h-2" />

                    {/* Speed up button */}
                    {activeSeries.status === 'production' && !prodStatus?.complete && (
                      <Button
                        className="w-full bg-gradient-to-r from-amber-600 to-orange-500 hover:from-amber-500 hover:to-orange-400 text-black text-xs font-bold h-8"
                        onClick={async () => {
                          setActionLoading('speedup');
                          try {
                            const res = await api.post(`/series-pipeline/${activeSeries.id}/speed-up-production`, {}, { timeout: 15000 });
                            toast.success(res.data.message);
                            if (refreshUser) refreshUser();
                            const ps = await api.get(`/series-pipeline/${activeSeries.id}/production-status`);
                            setProdStatus(ps.data);
                            if (ps.data.complete) setActiveSeries(prev => ({ ...prev, status: 'ready_to_release' }));
                          } catch (e) { toast.error(e.response?.data?.detail || 'Errore accelerazione'); }
                          finally { setActionLoading(null); }
                        }}
                        disabled={actionLoading}
                        data-testid="anime-speed-up-btn">
                        {actionLoading === 'speedup' ? <Loader2 className="w-3 h-3 animate-spin mr-1" /> : <span className="mr-1">⚡</span>}
                        Accelera Produzione (-30%)
                        <span className="ml-1 text-[9px] opacity-70">({(activeSeries.num_episodes || 12) <= 8 ? 15 : (activeSeries.num_episodes || 12) <= 16 ? 20 : 25} CP)</span>
                      </Button>
                    )}

                    {(prodStatus?.complete || activeSeries.status === 'ready_to_release') && (
                      <div className="space-y-2">
                        {/* Poster generation pre-release */}
                        {!activeSeries.poster_url && (
                          <Button className="w-full bg-purple-600 hover:bg-purple-500 text-white text-xs"
                            onClick={() => generatePosterQuick(activeSeries.id)} disabled={actionLoading || posterLoading === activeSeries.id}
                            data-testid="anime-pre-release-poster-btn">
                            {posterLoading === activeSeries.id ? <Loader2 className="w-3 h-3 animate-spin mr-1" /> : <Sparkles className="w-3 h-3 mr-1" />}
                            {posterLoading === activeSeries.id ? 'Generazione...' : 'Genera Locandina'}
                          </Button>
                        )}
                        {activeSeries.poster_url && (
                          <div className="flex items-center gap-2 p-2 bg-purple-500/5 rounded border border-purple-500/10">
                            <img src={posterSrc(activeSeries.poster_url)} alt="" className="w-8 h-12 rounded object-cover" />
                            <span className="text-[10px] text-purple-300 flex-1">Locandina pronta</span>
                            <button onClick={() => generatePosterQuick(activeSeries.id)} disabled={posterLoading === activeSeries.id}
                              className="text-[9px] text-purple-400 hover:underline">
                              {posterLoading === activeSeries.id ? 'Generazione...' : 'Rigenera'}
                            </button>
                          </div>
                        )}
                        {activeSeries.release_type === 'coming_soon' ? (
                          <div className="space-y-2" data-testid="anime-release-strategy">
                            <p className="text-xs font-bold text-white">Strategia di Uscita</p>
                            <div
                              className={`p-2.5 rounded-lg border cursor-pointer transition-all ${
                                animeReleaseStrategy === 'auto' ? 'border-yellow-500/60 bg-yellow-500/10' : 'border-gray-700/60 hover:border-gray-600'
                              }`}
                              onClick={() => { setAnimeReleaseStrategy('auto'); setAnimeManualHours(null); }}
                              data-testid="anime-strategy-auto">
                              <div className="flex items-start gap-2">
                                <Zap className="w-4 h-4 text-yellow-400 mt-0.5 flex-shrink-0" />
                                <div>
                                  <p className="text-[11px] font-bold text-white">Automatica</p>
                                  <p className="text-[9px] text-gray-500">Il sistema decide il momento migliore</p>
                                  <p className="text-[9px] text-emerald-400 mt-0.5">+3% incassi garantiti</p>
                                </div>
                              </div>
                            </div>
                            <div
                              className={`p-2.5 rounded-lg border cursor-pointer transition-all ${
                                animeReleaseStrategy === 'manual' ? 'border-cyan-500/60 bg-cyan-500/10' : 'border-gray-700/60 hover:border-gray-600'
                              }`}
                              onClick={() => setAnimeReleaseStrategy('manual')}
                              data-testid="anime-strategy-manual">
                              <div className="flex items-start gap-2">
                                <Target className="w-4 h-4 text-cyan-400 mt-0.5 flex-shrink-0" />
                                <div className="flex-1">
                                  <p className="text-[11px] font-bold text-white">Manuale</p>
                                  <p className="text-[9px] text-gray-500">Scegli quando uscire</p>
                                  <p className="text-[9px] text-amber-400 mt-0.5">Tempismo perfetto: +8% incassi!</p>
                                </div>
                              </div>
                              {animeReleaseStrategy === 'manual' && (
                                <div className="mt-2 grid grid-cols-4 gap-1.5 ml-6" data-testid="anime-manual-hours">
                                  {[6, 12, 24, 48].map(h => (
                                    <button key={h}
                                      className={`py-1.5 rounded text-[10px] font-medium border transition-all ${
                                        animeManualHours === h ? 'border-cyan-500 bg-cyan-500/15 text-cyan-400' : 'border-gray-700 text-gray-400 hover:border-gray-500'
                                      }`}
                                      onClick={(e) => { e.stopPropagation(); setAnimeManualHours(h); }}
                                      data-testid={`anime-manual-${h}h`}>
                                      {h}h
                                    </button>
                                  ))}
                                </div>
                              )}
                            </div>
                            <Button
                              className="w-full bg-gradient-to-r from-yellow-600 to-amber-600 hover:from-yellow-500 hover:to-amber-500 text-white font-bold"
                              disabled={!animeReleaseStrategy || (animeReleaseStrategy === 'manual' && !animeManualHours) || actionLoading}
                              onClick={async () => {
                                setActionLoading(true);
                                try {
                                  const res = await api.post(`/series-pipeline/${activeSeries.id}/choose-release-strategy`, {
                                    strategy: animeReleaseStrategy,
                                    hours: animeReleaseStrategy === 'manual' ? animeManualHours : 24
                                  });
                                  const d = res.data;
                                  const bonusMsg = d.bonus_pct > 0 ? ` Bonus: +${d.bonus_pct}%` : '';
                                  const perfectMsg = d.perfect_timing ? ' Tempismo perfetto!' : '';
                                  toast.success(`Strategia confermata! Uscita tra ${d.hours_until_release}h.${bonusMsg}${perfectMsg}`);
                                  setActiveSeries(null);
                                  setAnimeReleaseStrategy(null);
                                  setAnimeManualHours(null);
                                  loadData();
                                } catch (e) { toast.error(e.response?.data?.detail || 'Errore'); }
                                finally { setActionLoading(false); }
                              }}
                              data-testid="confirm-anime-strategy-btn">
                              {actionLoading ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : <Clock className="w-4 h-4 mr-2" />}
                              Conferma Strategia
                            </Button>
                          </div>
                        ) : (
                          <Button className="w-full bg-yellow-500 hover:bg-yellow-600 text-black font-bold" onClick={releaseSeries} disabled={actionLoading} data-testid="anime-release-btn">
                            {actionLoading ? <Loader2 className="w-4 h-4 animate-spin mr-2" /> : <Star className="w-4 h-4 mr-2" />}
                            Rilascia Anime!
                          </Button>
                        )}
                      </div>
                    )}
                  </CardContent>
                </Card>
              </motion.div>
            )}
          </div>
          </TabErrorBoundary>
        )}
      </div>

    {/* Cinematic Release Experience */}
    {releaseCard && releasePhase > 0 && (() => {
      const evt = releaseCard.release_event;
      const hasEvent = evt && evt.id !== 'quiet_release_series' && evt.id !== 'quiet_release_anime' && evt.id !== 'nothing_special';
      const isRare = hasEvent && evt.rarity === 'rare';

      return (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4" data-testid="anime-release-card-modal">
          <div className="absolute inset-0 bg-black/90 backdrop-blur-md"
            style={{ animation: 'rcFadeIn 0.5s ease-out' }}
            onClick={() => { if (releasePhase >= 3) closeReleaseCard(); }} />

          <div className="relative w-full max-w-sm z-10">
            {/* Phase 1: Title */}
            <div className="text-center mb-4" style={{ animation: 'rcSlideUp 0.8s ease-out both' }}>
              <Badge className="mx-auto mb-2 bg-pink-500/20 text-pink-400 text-[10px]"
                style={{ animation: 'rcFadeIn 0.5s ease-out 0.2s both' }}>
                Anime Completato!
              </Badge>
              <h1 className="text-xl font-black text-white tracking-tight"
                style={{ animation: 'rcScaleIn 0.6s ease-out 0.4s both' }}>
                {releaseCard.title}
              </h1>
              <p className="text-[10px] text-pink-400/70 uppercase mt-0.5"
                style={{ animation: 'rcFadeIn 0.4s ease-out 0.6s both' }}>
                {releaseCard.genre} - {releaseCard.episodes_count} episodi
              </p>
            </div>

            {/* Phase 2: Event reveal */}
            {releasePhase >= 2 && hasEvent && (() => {
              const borderC = evt.type === 'positive' ? 'border-emerald-500' : evt.type === 'negative' ? 'border-red-500' : 'border-amber-500';
              const bgGrad = evt.type === 'positive' ? 'from-emerald-950/80 to-[#111]' : evt.type === 'negative' ? 'from-red-950/80 to-[#111]' : 'from-amber-950/80 to-[#111]';
              const txtC = evt.type === 'positive' ? 'text-emerald-400' : evt.type === 'negative' ? 'text-red-400' : 'text-amber-400';
              const glowC = evt.type === 'positive' ? 'shadow-emerald-500/30' : evt.type === 'negative' ? 'shadow-red-500/30' : 'shadow-amber-500/30';

              return (
                <div className={`relative rounded-xl border-2 ${borderC} bg-gradient-to-b ${bgGrad} p-3.5 shadow-lg ${glowC} ${isRare ? 'ring-2 ring-purple-500/50' : ''}`}
                  style={{ animation: isRare ? 'rcShakeIn 0.7s ease-out both' : 'rcEventReveal 0.7s ease-out both' }}
                  data-testid="anime-release-event">
                  {isRare && <div className="absolute inset-0 rounded-xl overflow-hidden pointer-events-none">
                    <div className="absolute inset-0 bg-gradient-to-r from-transparent via-purple-500/10 to-transparent"
                      style={{ animation: 'rcShimmer 2s ease-in-out infinite' }} />
                  </div>}
                  <div className="flex justify-center mb-2">
                    <div className={`w-10 h-10 rounded-full flex items-center justify-center ${evt.type === 'positive' ? 'bg-emerald-500/20' : evt.type === 'negative' ? 'bg-red-500/20' : 'bg-amber-500/20'}`}
                      style={{ animation: 'rcPulse 1.5s ease-in-out infinite' }}>
                      <span className="text-xl">{evt.type === 'positive' ? '⚡' : evt.type === 'negative' ? '💥' : '🔀'}</span>
                    </div>
                  </div>
                  <div className="text-center mb-1.5">
                    {isRare && <Badge className="bg-purple-500/30 text-purple-300 text-[7px] mb-1 border border-purple-500/40">EVENTO RARO</Badge>}
                    <h3 className={`text-xs font-black ${txtC} uppercase tracking-wider`}>{evt.name}</h3>
                  </div>
                  <p className="text-[10px] text-gray-300 text-center leading-relaxed mb-2"
                    style={{ animation: 'rcFadeIn 0.5s ease-out 0.3s both' }}>{evt.description}</p>
                  <div className="flex justify-center gap-3 text-[10px] font-bold" style={{ animation: 'rcFadeIn 0.4s ease-out 0.5s both' }}>
                    {evt.quality_modifier !== 0 && (
                      <div className={`px-2 py-0.5 rounded-full ${evt.quality_modifier > 0 ? 'bg-emerald-500/15 text-emerald-400' : 'bg-red-500/15 text-red-400'}`}>
                        Qualita {evt.quality_modifier > 0 ? '+' : ''}{evt.quality_modifier}
                      </div>
                    )}
                    {evt.revenue_modifier !== 0 && (
                      <div className={`px-2 py-0.5 rounded-full ${evt.revenue_modifier > 0 ? 'bg-emerald-500/15 text-emerald-400' : 'bg-red-500/15 text-red-400'}`}>
                        Incassi {evt.revenue_modifier > 0 ? '+' : ''}{evt.revenue_modifier}%
                      </div>
                    )}
                  </div>
                </div>
              );
            })()}

            {/* Phase 3: Full results */}
            {releasePhase >= 3 && (
              <div className="mt-3 space-y-2" style={{ animation: 'rcSlideUp 0.6s ease-out both' }}>
                <Card className="bg-[#151517] border-pink-600/30 overflow-hidden">
                  <CardContent className="p-3 space-y-2.5">
                    <div className="flex items-center gap-3">
                      <div className="w-14 h-20 flex-shrink-0">
                        {releasePoster ? (
                          <img src={posterSrc(releasePoster)} alt="Locandina" className="w-full h-full object-cover rounded border border-pink-500/20 shadow-lg" />
                        ) : posterPolling ? (
                          <div className="w-full h-full rounded bg-pink-500/5 border-pink-500/20 border flex items-center justify-center animate-pulse">
                            <Sparkles className="w-4 h-4 text-pink-500/50" />
                          </div>
                        ) : (
                          <div className="w-full h-full rounded bg-pink-500/5 border border-white/5 flex items-center justify-center">
                            <Film className="w-5 h-5 text-gray-600" />
                          </div>
                        )}
                      </div>
                      <div className="flex-1">
                        <div className="grid grid-cols-3 gap-1.5 text-center">
                          <div className="p-1.5 rounded bg-pink-500/10 border border-pink-500/20">
                            <p className={`text-lg font-black ${releaseCard.quality?.score >= 70 ? 'text-green-400' : releaseCard.quality?.score >= 50 ? 'text-yellow-400' : 'text-red-400'}`}
                              style={{ animation: 'rcCountUp 0.5s ease-out both' }}>
                              {releaseCard.quality?.score || 0}
                            </p>
                            <p className="text-[7px] text-gray-500">QUALITA</p>
                          </div>
                          <div className="p-1.5 rounded bg-emerald-500/10 border border-emerald-500/20">
                            <p className="text-sm font-bold text-emerald-400">${((releaseCard.total_revenue || 0) / 1000000).toFixed(1)}M</p>
                            <p className="text-[7px] text-gray-500">INCASSO</p>
                          </div>
                          <div className="p-1.5 rounded bg-cyan-500/10 border border-cyan-500/20">
                            <p className="text-sm font-bold text-cyan-400">{releaseCard.audience_rating || 0}</p>
                            <p className="text-[7px] text-gray-500">VOTO</p>
                          </div>
                        </div>
                      </div>
                    </div>
                    <div className="flex flex-wrap gap-1 justify-center">
                      <Badge className="bg-purple-500/20 text-purple-400 text-[9px]">+{releaseCard.xp_reward} XP</Badge>
                      <Badge className="bg-pink-500/20 text-pink-400 text-[9px]">+{releaseCard.fame_bonus} Fama</Badge>
                      <Badge className="bg-cyan-500/20 text-cyan-400 text-[9px]">{releaseCard.episodes_count} ep.</Badge>
                    </div>
                    {releaseCard.audience_comments?.length > 0 && (
                      <div className="space-y-1">
                        <p className="text-[8px] text-gray-500 uppercase">Commenti</p>
                        {releaseCard.audience_comments.slice(0, 2).map((c, i) => (
                          <div key={i} className={`px-2 py-1 rounded text-[9px] border ${
                            c.sentiment === 'positive' ? 'bg-emerald-500/5 border-emerald-500/15 text-emerald-300' :
                            c.sentiment === 'negative' ? 'bg-red-500/5 border-red-500/15 text-red-300' :
                            'bg-amber-500/5 border-amber-500/15 text-amber-300'
                          }`}>
                            "{c.text}" <Badge className={`ml-1 text-[7px] h-3 ${c.rating >= 7 ? 'bg-emerald-500/20 text-emerald-400' : c.rating >= 5 ? 'bg-amber-500/20 text-amber-400' : 'bg-red-500/20 text-red-400'}`}>{c.rating}</Badge>
                          </div>
                        ))}
                      </div>
                    )}
                    <Button className="w-full bg-pink-600 hover:bg-pink-500 text-white text-xs font-bold"
                      onClick={closeReleaseCard} data-testid="close-anime-release-card">
                      Chiudi
                    </Button>
                  </CardContent>
                </Card>
              </div>
            )}
          </div>

          {/* CSS Animations */}
          <style>{`
            @keyframes rcFadeIn { from { opacity: 0; } to { opacity: 1; } }
            @keyframes rcSlideUp { from { opacity: 0; transform: translateY(25px); } to { opacity: 1; transform: translateY(0); } }
            @keyframes rcScaleIn { from { opacity: 0; transform: scale(0.85); } to { opacity: 1; transform: scale(1); } }
            @keyframes rcEventReveal { from { opacity: 0; transform: scale(0.9) translateY(12px); } to { opacity: 1; transform: scale(1) translateY(0); } }
            @keyframes rcShakeIn {
              0% { opacity: 0; transform: scale(0.8); }
              40% { opacity: 1; transform: scale(1.04); }
              55% { transform: scale(1) rotate(-1deg); }
              70% { transform: scale(1.02) rotate(1deg); }
              85% { transform: scale(1) rotate(-0.5deg); }
              100% { transform: scale(1) rotate(0); }
            }
            @keyframes rcShimmer { 0%, 100% { transform: translateX(-100%); } 50% { transform: translateX(100%); } }
            @keyframes rcCountUp { from { opacity: 0; transform: scale(0.5); } to { opacity: 1; transform: scale(1); } }
            @keyframes rcPulse { 0%, 100% { transform: scale(1); } 50% { transform: scale(1.08); } }
          `}</style>
        </div>
      );
    })()}
    </div>
  );
}
